#!/usr/bin/env python3
"""
Spelling Bee Proxy (spebe) — secure edition
Two endpoints:
  GET  /wordlists         -> word lists JSON for frontend on init
  POST /word/definition   -> { "word": "..." } -> definition sentence  
  POST /word/example      -> { "word": "..." } -> example sentence

Security:
  - Origin header validated against whitelist
  - Word validated against master list before any Anthropic call
  - Prompts constructed server-side; frontend never sends prompt text
  - No wildcard CORS

Local:
    set ANTHROPIC_API_KEY=sk-ant-...   (Windows)
    export ANTHROPIC_API_KEY=sk-ant-... (Mac/Linux)
    python proxy.py

Render: set ANTHROPIC_API_KEY in dashboard. PORT set automatically.
"""

from http.server import HTTPServer, SimpleHTTPRequestHandler
import urllib.request
import urllib.error
import unicodedata
import json
import os

PORT = int(os.environ.get("PORT", 8080))
ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY", "")
ANTHROPIC_URL = "https://api.anthropic.com/v1/messages"

ALLOWED_ORIGINS = {
    "https://spebe.onrender.com",
    "http://localhost:8080",
    "http://localhost:9000",
}

if not ANTHROPIC_API_KEY:
    print("WARNING: ANTHROPIC_API_KEY is not set!")
    print("  Windows:   set ANTHROPIC_API_KEY=sk-ant-...")
    print("  Mac/Linux: export ANTHROPIC_API_KEY=sk-ant-...")

